// PlayoffsMenu.js
import { useEffect, useState } from "react";
import { useNavigate } from "react-router-dom";

function PlayoffsMenu() {
    const [ligaSeleccionada, setLigaSeleccionada] = useState("");
    const [playoffs, setPlayoffs] = useState({});
    const [rondas, setRondas] = useState([]);
    const [rondaActiva, setRondaActiva] = useState(0);
    const navigate = useNavigate();

    useEffect(() => {
        const stored = JSON.parse(localStorage.getItem("playoffs_brackets")) || {};
        setPlayoffs(stored);
        const ligas = Object.keys(stored);
        if (ligas.length > 0) {
            setLigaSeleccionada(ligas[0]);
            setRondas(stored[ligas[0]]?.rondas || []);
        }
    }, []);

    useEffect(() => {
        if (ligaSeleccionada && playoffs[ligaSeleccionada]) {
            setRondas(playoffs[ligaSeleccionada]?.rondas || []);
            setRondaActiva(0);
        }
    }, [ligaSeleccionada]);

    const jugarPartido = (match, i) => {
        const nuevaRonda = [...rondas[rondaActiva]];
        const partidoActual = { ...match };
    
        // Simular ida si no estĂˇ jugada
        if (partidoActual.golesLocalIda === null || partidoActual.golesVisitanteIda === null) {
            partidoActual.golesLocalIda = Math.floor(Math.random() * 5);
            partidoActual.golesVisitanteIda = Math.floor(Math.random() * 5);
        }
        // Si ya hay ida, simular vuelta
        else if (partidoActual.golesLocalVuelta === null || partidoActual.golesVisitanteVuelta === null) {
            partidoActual.golesLocalVuelta = Math.floor(Math.random() * 5);
            partidoActual.golesVisitanteVuelta = Math.floor(Math.random() * 5);
            partidoActual.jugado = true;
        }
    
        nuevaRonda[i] = partidoActual;
    
        const nuevasRondas = [...rondas];
        nuevasRondas[rondaActiva] = nuevaRonda;
    
        const updatedPlayoffs = { ...playoffs };
        updatedPlayoffs[ligaSeleccionada].rondas = nuevasRondas;
    
        setRondas(nuevasRondas);
        setPlayoffs(updatedPlayoffs);
        localStorage.setItem("playoffs_brackets", JSON.stringify(updatedPlayoffs));
    };

 const avanzarRonda = () => {
    const ligaData = playoffs[ligaSeleccionada];
    const rondas = ligaData.rondas;

    const rondaActual = rondas[rondaActiva];
    if (!rondaActual || rondaActual.length === 0) {
        alert("No hay mĂˇs rondas que avanzar.");
        return;
    }

    const rondaCompleta = rondaActual.every(match => match.jugado);
    if (!rondaCompleta) {
        alert("Debes jugar todos los partidos de esta ronda antes de avanzar.");
        return;
    }

    const ganadores = rondaActual.map(p => {
        const idaLocal = p.golesLocalIda ?? 0;
        const idaVisitante = p.golesVisitanteIda ?? 0;
        const vueltaLocal = p.golesLocalVuelta ?? 0;
        const vueltaVisitante = p.golesVisitanteVuelta ?? 0;
        const totalLocal = idaLocal + vueltaLocal;
        const totalVisitante = idaVisitante + vueltaVisitante;

        return totalLocal >= totalVisitante ? p.local : p.visitante;
    });

    // âš ď¸Ź Generar final si estaba pendiente
    if (ligaData.finalPendiente) {
        if (ganadores.length === 2) {
            const final = createIdaYVueltaMatch(ganadores[0], ganadores[1]);
            rondas.push([final]);
            ligaData.finalPendiente = false;
            setRondas([...rondas]);
            setRondaActiva(rondaActiva + 1);
            localStorage.setItem("playoffs_brackets", JSON.stringify(playoffs));
            return;
        }
    }

    // Caso normal: generar nueva ronda si hay suficientes ganadores
    if (ganadores.length < 2) {
        alert("Playoffs finalizados.");
        return;
    }

    const nuevaRonda = [];
    for (let i = 0; i < ganadores.length; i += 2) {
        if (ganadores[i + 1]) {
            nuevaRonda.push(createIdaYVueltaMatch(ganadores[i], ganadores[i + 1]));
        }
    }

    rondas.push(nuevaRonda);
    setRondas([...rondas]);
    setRondaActiva(rondaActiva + 1);
    localStorage.setItem("playoffs_brackets", JSON.stringify(playoffs));
};

    const finalizarPlayoffs = () => {
        // AcĂˇ se debe:
        // - Cambiar ligas en localStorage.equipos segĂşn ganadores/perdedores
        // - Llamar a LeagueGeneration.js para nueva temporada
        alert("Ascensos/descensos aplicados. Comienza nueva temporada.");
        navigate("/generar-ligas");
    };
    function createIdaYVueltaMatch(local, visitante) {
        return {
            local,
            visitante,
            golesLocalIda: null,
            golesVisitanteIda: null,
            golesLocalVuelta: null,
            golesVisitanteVuelta: null,
            jugado: false,
            vueltaEnCasaDe: local.puntos >= visitante.puntos ? local.nombre : visitante.nombre
        };
    }
    const renderMatch = (match, i) => (
        <div key={i} className="match-card">
            <span>{match.local?.nombre} {match.golesLocal ?? "-"} vs {match.golesVisitante ?? "-"} {match.visitante?.nombre}</span>
            {!match.jugado && (
                <button onClick={() => jugarPartido(match, i)}>Jugar</button>
            )}
        </div>
    );

    return (
        <div className="playoffs-menu">
            <h1>Playoffs</h1>
            <select value={ligaSeleccionada} onChange={(e) => setLigaSeleccionada(e.target.value)}>
                {Object.keys(playoffs).map((liga, i) => (
                    <option key={i} value={liga}>{liga}</option>
                ))}
            </select>

            <h2>Ronda {rondaActiva + 1}</h2>
            <div className="ronda-matches">
                {Array.isArray(rondas[rondaActiva]) &&
                    rondas[rondaActiva].map((match, i) => renderMatch(match, i))}
            </div>

            <div className="playoff-controls">
                <button onClick={avanzarRonda}>Avanzar Ronda</button>
                <button onClick={finalizarPlayoffs}>Finalizar Playoffs</button>
            </div>
        </div>
    );
}

export default PlayoffsMenu;
